def remove_duplicates(arr):
    if not arr:
        return 0
    write_index = 1
    for i in range(1, len(arr)):
        if arr[i] != arr[write_index - 1]:
            arr[write_index] = arr[i]
            write_index += 1
    return write_index

n = int(input())
arr = list(map(int, input().split()))
print(remove_duplicates(arr))

def is_anagram(s1, s2):
    if len(s1) != len(s2):
        return False
    count = [0] * 26
    for c in s1:
        count[ord(c) - ord('a')] += 1
    for c in s2:
        count[ord(c) - ord('a')] -= 1
        if count[ord(c) - ord('a')] < 0:
            return False
    return True

s1 = input().strip()
s2 = input().strip()
print(str(is_anagram(s1, s2)).lower())

